    int n = s.length();
    vector<bool> replaced(n, false);
    vector<int> positions(n);

    // Record the positions of each character in the order
    for (int i = 0; i < n; ++i) {
        positions[order[i]] = i;
    }

    // Function to calculate the number of valid substrings
    auto countValidSubstrings = [&](vector<bool>& replaced) -> long long {
        long long total = 0;
        vector<int> lastStar(n, -1);

        for (int i = 0; i < n; ++i) {
            if (replaced[i]) {
                // Update the last star position
                lastStar[i] = i;
                // Count the number of substrings ending at i that contain at least one star
                total += i - lastStar[i] + 1;
            } else {
                // If there is a star before, add the number of substrings ending at i that contain at least one star
                if (lastStar[i] != -1) {
                    total += i - lastStar[i] + 1;
                }
            }
        }
        return total;
    };

    // Binary search for the minimum time t
    long long left = 0, right = n;
    long long answer = -1;

    while (left <= right) {
        long long mid = (left + right) / 2;
        vector<bool> replaced(n, false);

        for (int i = 0; i < mid; ++i) {
            replaced[order[i]] = true;
        }

        long long count = countValidSubstrings(replaced);
        if (count >= k) {
            answer = mid;
            right = mid - 1;
        } else {
            left = mid + 1;
        }
    }

    return answer;
}

